#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 50000
#define MAX_M 100000
#define INF INT_MAX

// Define the structure for a bus
typedef struct {
    int u, v, s, e;
} Bus;

// Define the structure for a priority queue node
typedef struct {
    int station, wait_time;
} PQNode;

// Compare function for the priority queue
int compare(const void *a, const void *b) {
    PQNode *node1 = (PQNode *)a;
    PQNode *node2 = (PQNode *)b;
    return node1->wait_time - node2->wait_time;
}

int main() {
    int N, T, M;
    scanf("%d %d %d", &N, &T, &M);
    Bus buses[M];
    for (int i = 0; i < M; i++) {
        scanf("%d %d %d %d", &buses[i].u, &buses[i].v, &buses[i].s, &buses[i].e);
    }
    // Create a graph from the buses
    int graph[N][N];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            graph[i][j] = INF;
        }
    }
    for (int i = 0; i < M; i++) {
        graph[buses[i].u - 1][buses[i].v - 1] = buses[i].e - buses[i].s;
    }
    // Run Dijkstra's algorithm
    int max_wait_time = 0;
    int visited[N];
    for (int i = 0; i < N; i++) {
        visited[i] = 0;
    }
    PQNode pq[N];
    int pq_size = 0;
    pq[pq_size].station = 0;
    pq[pq_size].wait_time = 0;
    pq_size++;
    while (pq_size > 0) {
        // Extract the node with the minimum wait time from the priority queue
        int min_idx = 0;
        for (int i = 1; i < pq_size; i++) {
            if (pq[i].wait_time < pq[min_idx].wait_time) {
                min_idx = i;
            }
        }
        PQNode min_node = pq[min_idx];
        // Remove the minimum node from the priority queue
        for (int i = min_idx; i < pq_size - 1; i++) {
            pq[i] = pq[i + 1];
        }
        pq_size--;
        // Mark the station as visited
        visited[min_node.station] = 1;
        // Update the maximum wait time
        max_wait_time = max_wait_time > min_node.wait_time ? max_wait_time : min_node.wait_time;
        // Add the neighbors to the priority queue
        for (int i = 0; i < N; i++) {
            if (!visited[i] && graph[min_node.station][i] != INF) {
                pq[pq_size].station = i;
                pq[pq_size].wait_time = min_node.wait_time + graph[min_node.station][i];
                pq_size++;
            }
        }
    }
    // Check if we can reach the destination station before the deadline
    if (visited[N - 1] && max_wait_time <= T) {
        printf("%d\n", max_wait_time);
    } else {
        printf("-1\n");
    }
    return 0;
}

