using namespace std;

// Define the structure for a bus
struct Bus {
    int u, v, s, e;
};

// Define the structure for a priority queue node
struct PQNode {
    int station, wait_time;
};

// Compare function for the priority queue
struct compare {
    bool operator()(const PQNode &a, const PQNode &b) {
        return a.wait_time > b.wait_time;
    }
};

int main() {
    int N, T, M;
    cin >> N >> T >> M;
    Bus buses[M];
    for (int i = 0; i < M; i++) {
        cin >> buses[i].u >> buses[i].v >> buses[i].s >> buses[i].e;
    }
    // Create a graph from the buses
    vector<vector<int>> graph(N, vector<int>(N, INT_MAX));
    for (int i = 0; i < M; i++) {
        graph[buses[i].u - 1][buses[i].v - 1] = buses[i].e - buses[i].s;
    }
    // Run Dijkstra's algorithm
    int max_wait_time = 0;
    vector<bool> visited(N, false);
    priority_queue<PQNode, vector<PQNode>, compare> pq;
    pq.push({0, 0});
    while (!pq.empty()) {
        // Extract the node with the minimum wait time from the priority queue
        PQNode min_node = pq.top();
        pq.pop();
        // Mark the station as visited
        visited[min_node.station] = true;
        // Update the maximum wait time
        max_wait_time = max(max_wait_time, min_node.wait_time);
        // Add the neighbors to the priority queue
        for (int i = 0; i < N; i++) {
            if (!visited[i] && graph[min_node.station][i] != INT_MAX) {
                pq.push({i, min_node.wait_time + graph[min_node.station][i]});
            }
        }
    }
    // Check if we can reach the destination station before the deadline
    if (visited[N - 1] && max_wait_time <= T) {
        cout << max_wait_time << endl;
    } else {
        cout << -1 << endl;
    }
    return 0;
}

