import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.Comparator;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int T = scanner.nextInt();
        int M = scanner.nextInt();
        int[][] buses = new int[M][4];
        for (int i = 0; i < M; i++) {
            buses[i][0] = scanner.nextInt();
            buses[i][1] = scanner.nextInt();
            buses[i][2] = scanner.nextInt();
            buses[i][3] = scanner.nextInt();
        }
        // Create a graph from the buses
        int[][] graph = new int[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                graph[i][j] = Integer.MAX_VALUE;
            }
        }
        for (int i = 0; i < M; i++) {
            graph[buses[i][0] - 1][buses[i][1] - 1] = buses[i][3] - buses[i][2];
        }
        // Run Dijkstra's algorithm
        int max_wait_time = 0;
        boolean[] visited = new boolean[N];
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[1]));
        pq.add(new int[] {0, 0});
        while (!pq.isEmpty()) {
            // Extract the node with the minimum wait time from the priority queue
            int[] min_node = pq.poll();
            // Mark the station as visited
            visited[min_node[0]] = true;
            // Update the maximum wait time
            max_wait_time = Math.max(max_wait_time, min_node[1]);
            // Add the neighbors to the priority queue
            for (int i = 0; i < N; i++) {
                if (!visited[i] && graph[min_node[0]][i] != Integer.MAX_VALUE) {
                    pq.add(new int[] {i, min_node[1] + graph[min_node[0]][i]});
                }
            }
        }
        // Check if we can reach the destination station before the deadline
        if (visited[N - 1] && max_wait_time <= T) {
            System.out.println(max_wait_time);
        } else {
            System.out.println(-1);
        }
    }
}

